#include <bits/stdc++.h>
using namespace std;
int main(){
    int n; cin >> n;
    vector<long long> a(n);
    for (auto &x : a) cin >> x;
    if (n == 1) { cout << a[0] << '\n'; return 0; }
    long long p2 = a[0], p1 = max(a[0], a[1]);
    for (int i = 2; i < n; i++){
        long long cur = max(p1, p2 + a[i]);
        p2 = p1; p1 = cur;
    }
    cout << p1 << '\n';
}
